 " + task [ "test" ] + f " 
 check( { task [ 'entry_point' ] } ) 
 " ) script_path = Path ( tmpdir ) / f " { task_id . replace ( '/' , '_' ) } .py" script_path . write_text ( script ) passed = safe_subprocess_run ( script_path , cwd = tmpdir ) task_results . append ({ "task_id" : task_id , "passed" : passed }) pass_count = sum ( 1 for r in task_results if r [ "passed" ]) fail_count = len ( task_results ) - pass_count total = len ( task_results ) pass_rate = pass_count / total if total > 0 else 0.0 summary = ( f "HumanEval subset: { pass_count } / { total } passed " f "(pass_rate= { pass_rate : .2% } , adapter_id= { adapter_id } )" ) print ( summary ) return { "pass_count" : pass_count , "fail_count" : fail_count , "pass_rate" : pass_rate , "task_results" : task_results , "summary" : summary , } run_kill_switch_gate ¶ run_kill_switch_gate ( baseline_pass1 : float , adapter_pass1 : float , threshold : float = 0.05 , ) -> dict [ str , object ] Compare baseline vs adapter Pass@1 scores and return a PASS/FAIL verdict. Computes the relative improvement of the adapter over the baseline and returns PASS if the improvement meets the threshold, FAIL otherwise. Parameters: Name Type Description Default baseline_pass1 float Pass@1 score for the baseline model (no adapter). required adapter_pass1 float Pass@1 score for the adapter model. required threshold float Minimum required relative improvement (default 0.05 = 5%). 0.05 Returns: Type Description dict [ str , object ] Dictionary with: - "baseline_pass1": float - "adapter_pass1": float - "relative_delta": float, relative improvement over baseline - "verdict": str, "PASS" or "FAIL" Example result = run_kill_switch_gate(0.50, 0.55) result["verdict"] 'PASS' Source code in libs/evaluation/src/evaluation/metrics.py 59 60 61 62 63 64 65 66 67 68 69 70 71 72 73 74 75 76 77 78 79 80 81 82 83 84 85 86 87 88 89 90 91 92 93 94 95 96 97 98 99 100 101 102 def run_kill_switch_gate ( baseline_pass1 : float , adapter_pass1 : float , threshold : float = 0.05 , ) -> dict [ str , object ]: """Compare baseline vs adapter Pass@1 scores and return a PASS/FAIL verdict. Computes the relative improvement of the adapter over the baseline and returns PASS if the improvement meets the threshold, FAIL otherwise. Args: baseline_pass1: Pass@1 score for the baseline model (no adapter). adapter_pass1: Pass@1 score for the adapter model. threshold: Minimum required relative improvement (default 0.05 = 5%). Returns: Dictionary with: - "baseline_pass1": float - "adapter_pass1": float - "relative_delta": float, relative improvement over baseline - "verdict": str, "PASS" or "FAIL" Example: >>> result = run_kill_switch_gate(0.50, 0.55) >>> result["verdict"] 'PASS' """ # 1e-9 prevents division-by-zero when baseline is 0.0 relative_delta = ( adapter_pass1 - baseline_pass1 ) / max ( baseline_pass1 , 1e-9 ) verdict = "PASS" if adapter_pass1 >= baseline_pass1 * ( 1 + threshold ) else "FAIL" print ( f "Kill-switch gate result: { verdict } 
 " f " Baseline Pass@1: { baseline_pass1 : .4f } 
 " f " Adapter Pass@1: { adapter_pass1 : .4f } 
 " f " Relative delta: { relative_delta : +.2% } (threshold: { threshold : +.0% } )" ) return { "baseline_pass1" : baseline_pass1 , "adapter_pass1" : adapter_pass1 , "relative_delta" : relative_delta , "verdict" : verdict , } score_adapter_quality ¶ score_adapter_quality ( adapter_id : str , pass_rate : float , generalization_delta : float | None = None , ) -> float Compute an overall quality score for an adapter. Aggregates the adapter's benchmark pass rate with its generalization performance (if available) into a single scalar quality score. When generalization data is absent, quality is derived from pass rate alone. Parameters: Name Type Description Default adapter_id str UUID of the adapter to score. required pass_rate float Fraction of benchmark tasks passed, in range 0.0 to 1.0. required generalization_delta float | None Optional difference between in-distribution and out-of-distribution (OOD) performance. Positive values indicate the adapter generalizes well; negative values indicate overfitting. Defaults to None (not measured). None Returns: Type Description float Quality score as a float between 0.0 and 1.0. Higher values indicate float a better overall adapter quality. Raises: Type Description NotImplementedError score_adapter_quality is not yet implemented. Example score = score_adapter_quality("adapter-001", pass_rate=0.85) score 0.85 score_with_gen = score_adapter_quality( ... "adapter-001", 0.85, generalization_delta=0.1, ... ) score_with_gen > score True Source code in libs/evaluation/src/evaluation/metrics.py 198 199 200 201 202 203 204 205 206 207 208 209 210 211 212 213 214 215 216 217 218 219 220 221 222 223 224 225 226 227 228 229 230 231 232 233 234 235 236 237 238 def score_adapter_quality ( adapter_id : str , pass_rate : float , generalization_delta : float | None = None , ) -> float : """Compute an overall quality score for an adapter. Aggregates the adapter's benchmark pass rate with its generalization performance (if available) into a single scalar quality score. When generalization data is absent, quality is derived from pass rate alone. Args: adapter_id: UUID of the adapter to score. pass_rate: Fraction of benchmark tasks passed, in range 0.0 to 1.0. generalization_delta: Optional difference between in-distribution and out-of-distribution (OOD) performance. Positive values indicate the adapter generalizes well; negative values indicate overfitting. Defaults to None (not measured). Returns: Quality score as a float between 0.0 and 1.0. Higher values indicate a better overall adapter quality. Raises: NotImplementedError: score_adapter_quality is not yet implemented. Example: >>> score = score_adapter_quality("adapter-001", pass_rate=0.85) >>> score 0.85 >>> score_with_gen = score_adapter_quality( ... "adapter-001", 0.85, generalization_delta=0.1, ... ) >>> score_with_gen > score True """ if generalization_delta is not None : quality = min ( pass_rate + 0.1 * max ( generalization_delta , 0 ), 1.0 ) else : quality = pass_rate return quality test_generalization ¶ test_generalization ( adapter_id : str , in_distribution_tasks : list [ str ] | None = None , ood_tasks : list [ str ] | None = None , ) -> dict [ str , Any ] Test whether an adapter generalizes beyond its training distribution. Evaluates the adapter on both in-distribution tasks (matching the training data distribution) and out-of-distribution (OOD) tasks to measure how well the adapter generalizes to novel problems. Parameters: Name Type Description Default adapter_id str UUID of the adapter to evaluate. required in_distribution_tasks list [ str ] | None Optional list of task IDs matching the adapter's training distribution. If None, uses a default in-distribution set. None ood_tasks list [ str ] | None Optional list of out-of-distribution task IDs to test generalization on. If None, uses a default OOD task set. None Returns: Type Description dict [ str , Any ] Dictionary with generalization results including: - "in_distribution_score": float,